/// {@category Controllers}
library;

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/check_result.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'ai_coach_report_controller.g.dart';

@riverpod
class AICoachReportController extends _$AICoachReportController {
  static final _logger = FimberLog('AICoachReportController');

  @override
  Future<AICoachReport?> build({
    required String teamId,
    String? reportId,
  }) async {
    return await _fetchReport();
  }

  Future<AICoachReport?> _fetchReport() async {
    if (reportId == null) return null;
    try {
      final result = await ref.read(repositoryProvider).getAIReport(
            teamId: teamId,
            reportId: reportId!,
          );

      checkResultForMaintenance(ref, result);

      if (result.hasLeft) {
        _logger.e('Failed to fetch AI coach report: $reportId',
            ex: result.left);
        throw result.left;
      }

      return result.right;
    } catch (e, stackTrace) {
      _logger.e('Error fetching AI coach report',
          ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  Future<void> refresh() async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() => _fetchReport());
  }
}

