import 'package:flutter/foundation.dart';
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_content.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_params.dart';

part 'ai_coach_report.freezed.dart';
part 'ai_coach_report.g.dart';

@freezed
abstract class AICoachReport with _$AICoachReport {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: FieldRename.none,
  )
  const factory AICoachReport({
    required String id,
    required String teamId,
    required AICoachReportParams params,
    required AICoachReportStatus status,
    required int retryCount,
    required DateTime createdAt,
    required DateTime updatedAt,
    DateTime? deletedAt,
    // content が生成中の場合は、null ではなく {} として返ってくる
    @JsonKey(
      fromJson: _contentFromJson,
      toJson: _contentToJson,
    )
    AICoachReportContent? content,
  }) = _AICoachReport;

  factory AICoachReport.fromJson(Map<String, dynamic> json) {
    return _$AICoachReportFromJson(json);
  }
}

enum AICoachReportStatus {
  accepted,
  completed,
  failed,
  cancelled,
}

AICoachReportContent? _contentFromJson(Map<String, dynamic>? json) {
  if (json == null || json.isEmpty) {
    return null;
  }

  try {
    return AICoachReportContent.fromJson(json);
  } catch (error, stackTrace) {
    debugPrint(
      'AICoachReportContent.fromJson failed: $error\n$stackTrace',
    );
    return null;
  }
}

Map<String, dynamic>? _contentToJson(AICoachReportContent? content) {
  return content?.toJson();
}

Map<String, dynamic> aiCoachReportToJson(AICoachReport report) {
  if (report is _AICoachReport) {
    return _$AICoachReportToJson(report);
  }
  throw ArgumentError('Unsupported AICoachReport type: ${report.runtimeType}');
}

